sys_script_include.script:
/**
 * @class RecordUpdater
 * @description 
 * @since 24/02/2026
 * @date  24/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class RecordUpdater extends Record {

    /**
     * @description Updates records from mention table based on given paramters
     *
     * @param {String} source application source 
     * @param {String} reason reason of the operation
     * @param {String} table The table to be used.
     * @param {String} sysId record sys_id
     * @param {Object} properties property object
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {String}  sys_id of the updated record. Returns null if the update fails.
     */
    // eslint-disable-next-line
    recordUpdate(source, reason, table, sysId, properties, stealth) {
        stealth = stealth || false;
        let result = '';
        const query = QueryBuilder.findRecordBySysId(sysId);

        if (UtilityFunctions.isValidTable(table) && UtilityFunctions.isValidRecord(table, query)) {

            const params = {
                'table': table,
                'column': 'sys_id',
                'identifier': sysId,
                'properties': JSON.stringify(properties),
                'stealth': UtilityFunctions.getBooleanValue(stealth),
                'result': ''
            };

            const script = ScriptBuider.getScriptRecordUpdate();

            result = new ScriptEvaluator().executScript('global', script, params);

            this.processResult(result, source, 'Record update', reason, table, properties);

        } else {
            this.LOG_HANDLER.error(source, 'Record update failed', reason, table, properties, {
                'sysId': sysId
            });
        }

        return result;
    }

    /**
     * @description Updates records from mention table based on mention query.
     *
     * @param {String} source application source 
     * @param {String} reason reason of the operation
     * @param {String} table The table to be used.
     * @param {String} query Encoded query
     * @param {Object} properties property object
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {String}  sys_id of the updated record. Returns null if the update fails.
     */
    // eslint-disable-next-line
    recordUpdateByQuery(source, reason, table, query, properties, stealth) {
        stealth = stealth || false;
        let result = '';

        if (UtilityFunctions.isValidTable(table) && UtilityFunctions.isValidRecord(table, query)) {

            const params = {
                'table': table,
                'query': query,
                'properties': JSON.stringify(properties),
                'stealth': UtilityFunctions.getBooleanValue(stealth),
                'result': ''
            };

            const script = ScriptBuider.getScriptRecordUpdateByQuery();

            result = new ScriptEvaluator().executScript('global', script, params);

            this.processResult(result, source, 'Record update', reason, table, properties);

        } else {
            this.LOG_HANDLER.error(source, 'Record update failed', reason, table, properties);
        }

        return result;
    }

    /**
     * @description Updates records from sys_dictionary_override based on given paramters
     *
     * @param {String} source application source 
     * @param {String} reason reason of the operation
     * @param {String} name table
     * @param {String} element column name
     * @param {String} override the attribute to override
     * @param {Boolean} checked true/false
     * @param {String} field dependent filed
     * @param {String} value field value
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {String}  sys_id of the updated record. Returns null if the update fails.
     */
    // eslint-disable-next-line
    dictionaryOverrideRecordUpdate(source, reason, name, element, override, checked, field, value, stealth) {
        stealth = stealth || false;
        let result = '';
        const query = QueryBuilder.findDictionaryOverride(UtilityFunctions.getBaseTable(name), name, element);
        const properties = {};
        properties[override] = checked;
        properties[field] = value;

        if (UtilityFunctions.isValidRecord('sys_dictionary_override', query)) {

            gs.debug('[RecordUpdater][dictionaryOverrideRecordUpdate] properties ==>' +
                JSON.stringify(properties));

            var params = {
                'table': 'sys_dictionary_override',
                'query': query,
                'properties': JSON.stringify(properties),
                'stealth': UtilityFunctions.getBooleanValue(stealth),
                'result': ''
            };

            const script = ScriptBuider.getScriptRecordUpdateByQuery();

            result = new ScriptEvaluator().executScript('global', script, params);

            this.processResult(result, source, 'Record update', reason, 'sys_dictionary_override', properties);

        } else {
            this.LOG_HANDLER.error(source, 'Record update failed', reason,
                'sys_dictionary_override', properties);
        }

        return result;
    }


    /**
     * @description Updates records from sys_dictionary based on given paramters
     *
     * @param {String} source application source 
     * @param {String} reason reason of the operation
     * @param {String} name table
     * @param {String} element column name
     * @param {String} field dependent field
     * @param {String} value the new field value
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {String}  sys_id of the updated record. Returns null if the update fails.
     */
    // eslint-disable-next-line
    dictionaryRecordUpdate(source, reason, name, element, field, value, stealth) {
        stealth = stealth || false;
        let result = '';
        const properties = {
            'field': field,
            'value': value
        };

        const tables = UtilityFunctions.getTables(name);
        const query = QueryBuilder.findDictionaryEntry(element, tables);
        gs.debug('[RecordUpdater][dictionaryRecordUpdate] query ==>' + query);

        const record = UtilityFunctions.getGlideRecord('sys_dictionary', query);

        if (record.next()) {
            gs.debug('[RecordUpdater][dictionaryRecordUpdate] record ==>' + record.getUniqueValue());

            const script = ScriptBuider.getScriptRecordSetValue();

            result = new ScriptEvaluator().runScript('global', script, 'sys_dictionary',
                record.getUniqueValue(), field, value, UtilityFunctions.getBooleanValue(stealth));

            this.processResult(result, source, 'Record update', reason, 'sys_dictionary', properties);

        } else {
            this.LOG_HANDLER.error(source, 'Record update failed', reason,
                'sys_dictionary', properties);
        }


        return result;
    }

    /**
     * @description Updates records from mention table based on given paramters
     *
     * @param {String} source application source 
     * @param {String} reason reason of the operation
     * @param {String} table The table to be used.
     * @param {String} sysId record sys_id
     * @param {String} field the field to update
     * @param {String} value the new field value
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {String}  sys_id of the updated record. Returns null if the update fails.
     */
    // eslint-disable-next-line
    recordUpdateValue(source, reason, table, sysId, field, value, stealth) {
        let result = '';
        const properties = {
            'field': field,
            'value': value
        };
        const query = QueryBuilder.findRecordBySysId(sysId);
        const record = UtilityFunctions.getGlideRecord(table, query);

        if (UtilityFunctions.isValidTable(table) && UtilityFunctions.isValidRecord(table, query)) {
            gs.debug('[RecordUpdater][dictionaryRecordUpdate] record ==>' + record.getUniqueValue());

            const script = ScriptBuider.getScriptRecordSetValue();

            result = new ScriptEvaluator().runScript('global', script, table,
                sysId, field, value, UtilityFunctions.getBooleanValue(stealth));


            this.processResult(result, source, 'Update value', reason, table, properties);

        } else {
            this.LOG_HANDLER.error(source, 'Update value', reason,
                'sys_dictionary_override', properties);
        }

		return result;
    }

}
